package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetTrimDefaultFalse() {
        // Using DEFAULT constant which has trim = false
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrimTrue() {
        // Create a CSVFormat with trim = true using withTrim(true)
        CSVFormat format = CSVFormat.DEFAULT.withTrim(true);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrimFalseExplicit() {
        // Create a CSVFormat with trim = false explicitly
        CSVFormat format = CSVFormat.DEFAULT.withTrim(false);
        assertFalse(format.getTrim());
    }
}
